-- Recolour the Aria theme preview image to Aria's ACTUAL palette (deep green
-- accent #2F5D4F on paper #F6F4EF) — the prior preview used the wrong (orange)
-- palette. Inline SVG data URI; passes through websiteAssetUrl unchanged.
UPDATE public.site_themes
SET preview_image_path = 'data:image/svg+xml;base64,'
WHERE slug = 'aria';
